69	  begin
70	    if rising_edge(clk_i) then
71	      -- *** Stage 0 ***
72	      if vld_a_i = '1' then
73	        InAReg0 <= dat_a_i;
74	      end if;
75	      if vld_b_i = '1' then
76	        InBReg0 <= dat_b_i;
77	      end if;
78	      -- If B is used as data port, calculations must be updated on new B values
79	      if not in_b_is_coef_g then
80	        Vld0 <= vld_a_i or vld_b_i;
81	      -- If B is used as asynchronously updated coefficient, a change to the coefficient does not lead to an output sample
82	      else
83	        Vld0 <= vld_a_i;
84	      end if;
